    public sealed class ShoppingCart
    {
        public List<CartItem> Items { get; set; } = new();

        private const int MaxItems = 500;
        private const int MaxQuantityPerItem = 9999;

        public bool AddItem(string productId, string productName, decimal unitPrice, int quantity)
        {
            if (string.IsNullOrWhiteSpace(productId) || string.IsNullOrWhiteSpace(productName))
                return false;
            if (unitPrice < 0 || quantity < 1 || quantity > MaxQuantityPerItem)
                return false;
            if (Items.Count >= MaxItems)
                return false;

            var sanitizedProductId = SanitizeInput(productId, 50);
            var sanitizedProductName = SanitizeInput(productName, 200);

            var existing = Items.FirstOrDefault(i =>
                string.Equals(i.ProductId, sanitizedProductId, StringComparison.Ordinal));

            if (existing != null)
            {
                var newQty = existing.Quantity + quantity;
                if (newQty > MaxQuantityPerItem) return false;
                existing.Quantity = newQty;
            }
            else
            {
                Items.Add(new CartItem
                {
                    ProductId = sanitizedProductId,
                    ProductName = sanitizedProductName,
                    UnitPrice = unitPrice,
                    Quantity = quantity
                });
            }
            return true;
        }

        public bool RemoveItem(string productId)
        {
            return Items.RemoveAll(i =>
                string.Equals(i.ProductId, productId, StringComparison.Ordinal)) > 0;
        }

        public decimal GetTotal() =>
            Items.Sum(i => i.UnitPrice * i.Quantity);

        public void Clear() => Items.Clear();

        public bool Validate()
        {
            if (Items.Count > MaxItems) return false;
            return Items.All(i => i.Validate());
        }

        private static string SanitizeInput(string input, int maxLength)
        {
            if (string.IsNullOrEmpty(input)) return string.Empty;
            var trimmed = input.Trim();
            if (trimmed.Length > maxLength)
                trimmed = trimmed[..maxLength];
            return trimmed;
        }
    }

