            ArgumentNullException.ThrowIfNull(session);

            var jsonBytes = JsonSerializer.SerializeToUtf8Bytes(session, _jsonOptions);
            var hmac = ComputeHmac(jsonBytes);

            // Format: [4 bytes HMAC length][HMAC][JSON data]
            var result = new byte[4 + hmac.Length + jsonBytes.Length];
            BitConverter.GetBytes(hmac.Length).CopyTo(result, 0);
            hmac.CopyTo(result, 4);
            jsonBytes.CopyTo(result, 4 + hmac.Length);

            return result;
        }

        public UserSession? Deserialize(byte[] data)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            if (data == null || data.Length < 4 + 32) // minimum: 4 byte length + 32 byte HMAC
                return null;

            try
            {
                var hmacLength = BitConverter.ToInt32(data, 0);
                if (hmacLength != 32 || data.Length < 4 + hmacLength + 1)
                    return null;

                var storedHmac = new byte[hmacLength];
                Array.Copy(data, 4, storedHmac, 0, hmacLength);

                var jsonBytes = new byte[data.Length - 4 - hmacLength];
                Array.Copy(data, 4 + hmacLength, jsonBytes, 0, jsonBytes.Length);

                // Verify integrity before deserialization
                var computedHmac = ComputeHmac(jsonBytes);
                if (!CryptographicOperations.FixedTimeEquals(storedHmac, computedHmac))
                {
                    // Tampering detected
                    return null;
                }

                // Enforce size limit to prevent resource exhaustion
                const int maxSessionSizeBytes = 1024 * 1024; // 1 MB
                if (jsonBytes.Length > maxSessionSizeBytes)
                    return null;

                var session = JsonSerializer.Deserialize<UserSession>(jsonBytes, _jsonOptions);

                // Post-deserialization validation
                if (session != null && !ValidateSession(session))
                    return null;

                return session;
            }
            catch (JsonException)
            {
                return null;
            }
        }

        private byte[] ComputeHmac(byte[] data)
        {
            using var hmac = new HMACSHA256(_hmacKey);
            return hmac.ComputeHash(data);
        }

        private static bool ValidateSession(UserSession session)
