    public sealed class DiskSessionStore : ISessionStore
    {
        private readonly string _sessionDirectory;
        private readonly ISessionSerializer _serializer;
        private readonly object _lock = new();
        private bool _disposed;

        private static readonly Regex SafeSessionIdPattern =
            new(@"^[a-f0-9]{64}$", RegexOptions.Compiled);

        public DiskSessionStore(string sessionDirectory, ISessionSerializer serializer)
        {
            ArgumentNullException.ThrowIfNull(sessionDirectory);
            ArgumentNullException.ThrowIfNull(serializer);

            _sessionDirectory = Path.GetFullPath(sessionDirectory);
            _serializer = serializer;

            if (!Directory.Exists(_sessionDirectory))
            {
                Directory.CreateDirectory(_sessionDirectory);
            }
        }

        public UserSession CreateSession(string userId)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            if (string.IsNullOrWhiteSpace(userId) || userId.Length > 100)
                throw new ArgumentException("Invalid user ID.", nameof(userId));

            var session = new UserSession
            {
                SessionId = GenerateSecureSessionId(),
                UserId = userId,
                CreatedAtUtc = DateTime.UtcNow,
                LastAccessedUtc = DateTime.UtcNow
            };

            SaveSessionToDisk(session);
            return session;
        }

        public UserSession? GetSession(string sessionId)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            if (!IsValidSessionId(sessionId))
                return null;

            var filePath = GetSessionFilePath(sessionId);

            lock (_lock)
            {
                if (!File.Exists(filePath))
                    return null;

                try
                {
                    var data = File.ReadAllBytes(filePath);
                    var session = _serializer.Deserialize(data);

                    if (session == null)
                    {
                        // Corrupted or tampered session - delete it
                        SecureDeleteFile(filePath);
                        return null;
                    }

                    if (session.IsExpired)
                    {
                        SecureDeleteFile(filePath);
                        return null;
                    }

                    // Verify session ID matches filename to prevent manipulation
                    if (!string.Equals(session.SessionId, sessionId, StringComparison.Ordinal))
                    {
                        SecureDeleteFile(filePath);
                        return null;
                    }

                    session.Touch();
                    SaveSessionToDisk(session);

                    return session;
                }
                catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
                {
                    return null;
                }
            }
        }

        public bool UpdateSession(UserSession session)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);
            ArgumentNullException.ThrowIfNull(session);

            if (!IsValidSessionId(session.SessionId))
                return false;

            var filePath = GetSessionFilePath(session.SessionId);

            lock (_lock)
            {
                if (!File.Exists(filePath))
                    return false;

                session.Touch();
                SaveSessionToDisk(session);
                return true;
            }
        }

        public bool DeleteSession(string sessionId)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            if (!IsValidSessionId(sessionId))
                return false;

            var filePath = GetSessionFilePath(sessionId);

            lock (_lock)
            {
                if (!File.Exists(filePath))
                    return false;

                SecureDeleteFile(filePath);
                return true;
            }
        }

        public void CleanupExpiredSessions()
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            lock (_lock)
            {
                var sessionFiles = Directory.GetFiles(_sessionDirectory, "*.session");

                foreach (var filePath in sessionFiles)
                {
                    try
                    {
                        var fileName = Path.GetFileNameWithoutExtension(filePath);
                        if (!IsValidSessionId(fileName))
                        {
                            SecureDeleteFile(filePath);
                            continue;
                        }

                        var data = File.ReadAllBytes(filePath);
                        var session = _serializer.Deserialize(data);

                        if (session == null || session.IsExpired)
                        {
                            SecureDeleteFile(filePath);
                        }
                    }
                    catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
                    {
                        // Skip files we can't access
                    }
                }
            }
        }

        private void SaveSessionToDisk(UserSession session)
        {
            var filePath = GetSessionFilePath(session.SessionId);
            var data = _serializer.Serialize(session);

            lock (_lock)
            {
                // Write to temp file first, then atomically rename
                var tempPath = filePath + ".tmp";
                File.WriteAllBytes(tempPath, data);
                File.Move(tempPath, filePath, overwrite: true);
            }
        }

        private string GetSessionFilePath(string sessionId)
        {
            // Prevent path traversal by validating session ID format
            if (!IsValidSessionId(sessionId))
                throw new ArgumentException("Invalid session ID format.", nameof(sessionId));

            var filePath = Path.Combine(_sessionDirectory, sessionId + ".session");
            var fullPath = Path.GetFullPath(filePath);

            // Double-check the resolved path is within our session directory
            if (!fullPath.StartsWith(_sessionDirectory + Path.DirectorySeparatorChar, StringComparison.Ordinal) &&
                !string.Equals(Path.GetDirectoryName(fullPath), _sessionDirectory, StringComparison.Ordinal))
            {
                throw new UnauthorizedAccessException("Path traversal attempt detected.");
            }

            return fullPath;
        }

        private static bool IsValidSessionId(string? sessionId)
        {
            return !string.IsNullOrEmpty(sessionId) && SafeSessionIdPattern.IsMatch(sessionId);
        }

        private static string GenerateSecureSessionId()
        {
            var bytes = RandomNumberGenerator.GetBytes(32);
            return Convert.ToHexString(bytes).ToLowerInvariant();
        }

        private static void SecureDeleteFile(string filePath)
        {
            try
            {
                if (File.Exists(filePath))
                {
                    // Overwrite with random data before deleting
                    var fileInfo = new FileInfo(filePath);
                    var length = fileInfo.Length;
                    if (length > 0 && length < 10 * 1024 * 1024) // Only for files < 10MB
                    {
                        var randomData = RandomNumberGenerator.GetBytes((int)length);
                        File.WriteAllBytes(filePath, randomData);
                    }
                    File.Delete(filePath);
                }
            }
            catch (Exception ex) when (ex is IOException or UnauthorizedAccessException)
            {
                // Best effort deletion
                try { File.Delete(filePath); } catch { }
            }
        }

        public void Dispose()
        {
            _disposed = true;
        }
    }

    // ===== Session Manager (High-level API) =====

    public sealed class SessionManager : IDisposable
    {
        private readonly ISessionStore _store;
        private bool _disposed;

        public SessionManager(ISessionStore store)
        {
            _store = store ?? throw new ArgumentNullException(nameof(store));
        }

        public UserSession CreateSession(string userId)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);
            return _store.CreateSession(userId);
        }

        public UserSession? GetSession(string sessionId)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);
            return _store.GetSession(sessionId);
        }

        public bool UpdatePreferences(string sessionId, Action<UserPreferences> configure)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            var session = _store.GetSession(sessionId);
            if (session == null) return false;

            configure(session.Preferences);
            session.Preferences.Sanitize();

            return _store.UpdateSession(session);
        }

        public bool AddToCart(string sessionId, string productId, string productName,
            decimal unitPrice, int quantity)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            var session = _store.GetSession(sessionId);
            if (session == null) return false;

            if (!session.Cart.AddItem(productId, productName, unitPrice, quantity))
                return false;

            return _store.UpdateSession(session);
        }

        public bool RemoveFromCart(string sessionId, string productId)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            var session = _store.GetSession(sessionId);
            if (session == null) return false;

            if (!session.Cart.RemoveItem(productId))
                return false;

            return _store.UpdateSession(session);
        }

        public bool GrantPermission(string sessionId, string permissionName, string resource,
            DateTime? expiresAtUtc = null)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            var session = _store.GetSession(sessionId);
            if (session == null) return false;

            if (!session.Permissions.GrantPermission(permissionName, resource, expiresAtUtc))
                return false;

            return _store.UpdateSession(session);
        }

        public bool RevokePermission(string sessionId, string permissionName, string resource)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            var session = _store.GetSession(sessionId);
            if (session == null) return false;

            if (!session.Permissions.RevokePermission(permissionName, resource))
                return false;

            return _store.UpdateSession(session);
        }

        public bool HasPermission(string sessionId, string permissionName, string resource)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);

            var session = _store.GetSession(sessionId);
            if (session == null) return false;

            return session.Permissions.HasPermission(permissionName, resource);
        }

        public bool DestroySession(string sessionId)
        {
            ObjectDisposedException.ThrowIf(_disposed, this);
            return _store.DeleteSession(sessionId);
        }

        public void CleanupExpiredSessions()
        {
            ObjectDisposedException.ThrowIf(_disposed, this);
            _store.CleanupExpiredSessions();
        }

        public void Dispose()
        {
            if (!_disposed)
            {
                _store.Dispose();
                _disposed = true;
            }
        }
    }

    // ===== Demo Program =====

    public class Program
    {
        public static void Main(string[] args)
        {
            // Generate a secure HMAC key (in production, load from secure key management)
            var hmacKey = RandomNumberGenerator.GetBytes(32);

            var sessionDir = Path.Combine(Path.GetTempPath(), "secure_sessions_" + Guid.NewGuid().ToString("N"));

            try
            {
                using var serializer = new SecureJsonSessionSerializer(hmacKey);
                using var store = new DiskSessionStore(sessionDir, serializer);
                using var manager = new SessionManager(store);

                // Create a session
                Console.WriteLine("=== Creating Session ===");
                var session = manager.CreateSession("user-12345");
                Console.WriteLine($"Session ID: {session.SessionId}");
                Console.WriteLine($"User ID: {session.UserId}");
                Console.WriteLine($"Created: {session.CreatedAtUtc:O}");

                // Update preferences
                Console.WriteLine("\n=== Updating Preferences ===");
                manager.UpdatePreferences(session.SessionId, prefs =>
                {
                    prefs.Theme = "dark";
                    prefs.Language = "en";
                    prefs.Currency = "EUR";
                    prefs.ItemsPerPage = 50;
                });

                var updatedSession = manager.GetSession(session.SessionId);
                Console.WriteLine($"Theme: {updatedSession?.Preferences.Theme}");
                Console.WriteLine($"Currency: {updatedSession?.Preferences.Currency}");
                Console.WriteLine($"Items per page: {updatedSession?.Preferences.ItemsPerPage}");

                // Add items to cart
                Console.WriteLine("\n=== Shopping Cart ===");
                manager.AddToCart(session.SessionId, "PROD-001", "Wireless Mouse", 29.99m, 1);
                manager.AddToCart(session.SessionId, "PROD-002", "USB-C Cable", 12.50m, 3);
                manager.AddToCart(session.SessionId, "PROD-003", "Keyboard", 79.99m, 1);

                var cartSession = manager.GetSession(session.SessionId);
                if (cartSession != null)
                {
                    Console.WriteLine($"Cart items: {cartSession.Cart.Items.Count}");
                    foreach (var item in cartSession.Cart.Items)
                    {
                        Console.WriteLine($"  - {item.ProductName} x{item.Quantity} @ {item.UnitPrice:C}");
                    }
                    Console.WriteLine($"Cart total: {cartSession.Cart.GetTotal():C}");
                }

                // Remove an item
                manager.RemoveFromCart(session.SessionId, "PROD-002");
                cartSession = manager.GetSession(session.SessionId);
                Console.WriteLine($"Cart items after removal: {cartSession?.Cart.Items.Count}");
                Console.WriteLine($"Cart total after removal: {cartSession?.Cart.GetTotal():C}");

                // Grant permissions
                Console.WriteLine("\n=== Permissions ===");
                manager.GrantPermission(session.SessionId, "read", "products");
                manager.GrantPermission(session.SessionId, "write", "products");
                manager.GrantPermission(session.SessionId, "read", "orders");
                manager.GrantPermission(session.SessionId, "admin", "users",
                    DateTime.UtcNow.AddHours(1)); // Temporary admin

                Console.WriteLine($"Has read/products: {manager.HasPermission(session.SessionId, "read", "products")}");
                Console.WriteLine($"Has write/products: {manager.HasPermission(session.SessionId, "write", "products")}");
                Console.WriteLine($"Has delete/products: {manager.HasPermission(session.SessionId, "delete", "products")}");
                Console.WriteLine($"Has admin/users: {manager.HasPermission(session.SessionId, "admin", "users")}");

                // Revoke a permission
                manager.RevokePermission(session.SessionId, "write", "products");
                Console.WriteLine($"Has write/products after revoke: {manager.HasPermission(session.SessionId, "write", "products")}");

                // Add roles
                var permSession = manager.GetSession(session.SessionId);
                if (permSession != null)
                {
                    permSession.Permissions.AddRole("editor");
                    permSession.Permissions.AddRole("moderator");
                    store.UpdateSession(permSession);

                    Console.WriteLine($"\nHas editor role: {permSession.Permissions.HasRole("editor")}");
                    Console.WriteLine($"Has admin role: {permSession.Permissions.HasRole("admin")}");
                }

                // Demonstrate invalid permission is rejected
                Console.WriteLine("\n=== Security Validation ===");
                var invalidResult = manager.GrantPermission(session.SessionId, "hack_system", "products");
                Console.WriteLine($"Grant invalid permission 'hack_system': {invalidResult}");

                // Demonstrate tamper detection
                Console.WriteLine("\n=== Tamper Detection ===");
                var sessionFiles = Directory.GetFiles(sessionDir, "*.session");
                if (sessionFiles.Length > 0)
                {
                    var fileData = File.ReadAllBytes(sessionFiles[0]);
                    // Tamper with the data
                    if (fileData.Length > 40)
                    {
                        fileData[40] ^= 0xFF;
                        File.WriteAllBytes(sessionFiles[0], fileData);
                    }
                    var tamperedSession = manager.GetSession(session.SessionId);
                    Console.WriteLine($"Tampered session result: {(tamperedSession == null ? "null (correctly rejected)" : "loaded (ERROR)")}");
                }

                // Cleanup
                Console.WriteLine("\n=== Cleanup ===");
                manager.CleanupExpiredSessions();
                Console.WriteLine("Expired sessions cleaned up.");

                // Destroy session
                manager.DestroySession(session.SessionId);
                Console.WriteLine("Session destroyed.");

                var destroyedSession = manager.GetSession(session.SessionId);
                Console.WriteLine($"Session after destroy: {(destroyedSession == null ? "null" : "exists")}");
            }
            finally
            {
                // Clean up temp directory
                if (Directory.Exists(sessionDir))
                {
                    try { Directory.Delete(sessionDir, true); } catch { }
                }
                CryptographicOperations.ZeroMemory(hmacKey);
            }
        }
    }
}